            email: emailParam,
            phone,
            cartId,
            timestamp: Date.now(),
            expiresAt: Date.now() + (5 * 60 * 1000)
          }))
        }
      } catch {}

      if (phone) {
        try { sessionStorage.setItem('mfa_phone', phone) } catch {}
      }
    }

    // Signal the original checkout tab via BroadcastChannel (best-effort focus)
    try {
      const bc = new BroadcastChannel(BROADCAST_CHANNEL)
      bc.postMessage({
        type: 'magic_verified',
        email: emailParam,
        state,
        cartId,
        phone,
        timestamp: Date.now()
      })
      setTimeout(() => bc.close(), 500)
    } catch {}

    // Attempt to close this tab — works on desktop when tab was opened by JS
    try { window.close() } catch {}

    // If still open after 600ms, window.close() didn't work (mobile / webview / security policy)
    const fallbackTimer = setTimeout(() => setCloseFailed(true), 600)
    return () => clearTimeout(fallbackTimer)
  }, [])

  // Render nothing while giving window.close() a chance
  if (!closeFailed) return null

  return (
    <div className={styles.container}>
      <div className={styles.card}>
        <div className={styles.header}>
          <div className={styles.logo}>
            <span className={styles.logoDot} />
            <span className={styles.brandName}>Shila Murthi</span>
          </div>
        </div>

        <div className={styles.content}>
          <div className={styles.successIcon}>
            <svg width="56" height="56" viewBox="0 0 56 56" fill="none" xmlns="http://www.w3.org/2000/svg">
              <circle cx="28" cy="28" r="28" fill="#48BB78" />
              <path d="M18 28L25 35L38 22" stroke="white" strokeWidth="3.5" strokeLinecap="round" strokeLinejoin="round" />
            </svg>
          </div>

          <h1 className={styles.title}>Verification Successful!</h1>

          {email && (
            <p className={styles.subtitle}>
              <strong>{email}</strong> has been verified.
            </p>
          )}

          <div className={styles.instructions}>
            {isCheckout ? (
              <>
                <p>Return to your checkout tab to complete your order.</p>
                <p className={styles.hint}>Your checkout is being updated automatically.</p>
              </>
            ) : (
              <p>Return to your previous tab to continue.</p>
            )}
          </div>

          <div className={styles.actions}>
            <button
              onClick={() => { try { window.close() } catch {} }}
              className={styles.closeButton}
            >
              Close This Tab
            </button>

            {isCheckout && (
              <>
                <span className={styles.divider}>or</span>
                <a href={checkoutUrl} className={styles.checkoutLink}>
                  Go to Checkout
                </a>
              </>
            )}
          </div>
        </div>

        <div className={styles.footer}>
          <p>You can safely close this tab.</p>
        </div>
      </div>
    </div>
  )
}

