// Listen for cross-tab verification success (when magic link opens in new tab)
useEffect(() => {
  const checkCrossTabVerification = async () => {
    try {
      const raw = localStorage.getItem('magic_verification_success')
      if (!raw) return
      const data = JSON.parse(raw)

      // Clean up expired data
      if (data?.expiresAt && data.expiresAt <= Date.now()) {
        localStorage.removeItem('magic_verification_success')
        return
      }

      if (!data?.verified || !data?.email || !data?.cartId || data.cartId !== cart?.id) return

      // Prevent duplicate verify calls (polling handler may also be running)
      if (verifyInProgressRef.current) return
      verifyInProgressRef.current = true

      // Clear localStorage immediately to prevent re-processing
      localStorage.removeItem('magic_verification_success')

      // Set UI state
      setEmail(data.email)
      setIdentityMethod('email')
      setMagicSent(true)
      setMagicVerified(true)

      // Stop the magic link polling since we know it's verified
      if (magicPollTimerRef.current) {
        clearInterval(magicPollTimerRef.current)
        magicPollTimerRef.current = null
      }

      // Call verify endpoint to get customerId (required for payment)
      const fullName = (formData.name || '').trim()
      const nameParts = fullName.split(/\s+/).filter(Boolean)
      const firstName = nameParts[0] || 'Customer'
      const lastName = nameParts.length > 1 ? nameParts.slice(1).join(' ') : ''

      const verifyPayload = {
        email: data.email,
        cartId: data.cartId,
        phone: data.phone || formData.contactNumber || phone || '',
        formData: {
          first_name: firstName,
          last_name: lastName,
          phone: data.phone || formData.contactNumber || phone || '',
          address: {
            address_1: formData.address,
            city: formData.city,
            postal_code: formData.postalCode,
            province: formData.state,
            country_code: 'in',
            phone: data.phone || formData.contactNumber || phone || ''
          }
        }
      }

      const cr = await fetch('/api/auth/session/checkout/verify', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(verifyPayload)
      })
      const cj = await cr.json().catch(() => ({}))

      if (cr.ok && cj?.ok === true && cj.customerId) {
        setCustomerId(String(cj.customerId))
        try { await setCustomerIdHybrid(String(cj.customerId)) } catch {}
        setPurchaseReady(true)
        setIdentityError(null)

        // Auto-login via NextAuth
        try {
          const { signIn } = await import('next-auth/react')
          await signIn('session', {
            identifier: data.email.trim().toLowerCase(),
            customerId: String(cj.customerId),
            redirect: false
          })
        } catch {}
      } else {
        // Verify failed — don't block, let user know to retry
        console.error('[CrossTab] verify failed:', cj?.error)
        setIdentityError('Verification detected but setup incomplete. Please click "Resend Magic Link" to retry.')
      }

      verifyInProgressRef.current = false
    } catch (e) {
      verifyInProgressRef.current = false
    }
  }

  // Check immediately
