        const customerIdValue = String(cj.customerId)
        setCustomerId(customerIdValue)
        try { await setCustomerIdHybrid(customerIdValue) } catch {}
        setPurchaseReady(true)
        setIdentityError(null)
        verifySuccess = true

        // Auto-login via NextAuth
        try {
          const identifierValue = (identityMethod === 'email')
            ? (em || '').trim().toLowerCase()
            : (phone || '').trim()
          if (identifierValue) {
            const { signIn } = await import('next-auth/react')
            await signIn('session', {
              identifier: identifierValue,
              customerId: customerIdValue,
              redirect: false
            })
          }
        } catch {}
      } else {
        console.warn(`[POLL] verify attempt ${retryAttempt + 1} failed:`, cj?.error)
      }
    } catch (fetchErr) {
      console.error(`[POLL] verify fetch error attempt ${retryAttempt + 1}:`, fetchErr)
    }
  }

  if (!verifySuccess) {
    setIdentityError(mapIdentityError('checkout-verify', 'not_verified', 400))
  }

  verifyInProgressRef.current = false
}

