            <div className={loginStyles.modalActions}>
              <button
                className={loginStyles.modalLink}
                onClick={sendOtp}
                disabled={otpSending}
              >
                {otpSending ? 'Sending...' : 'Resend OTP'}
              </button>
              <button
                className={loginStyles.modalLink}
                onClick={() => {
                  setShowOtpModal(false)
                  setOtpCode('')
                }}
              >
                Change Number
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
