    sessionTTL: getSessionConfig().SESSION_TTL_DAYS + ' days'
  })

  // Create temporary verification marker and confirm it's readable before redirecting.
  // Cloudflare KV is eventually consistent — writes can take 1-2s to propagate.
  // Without this read-back check, the verify endpoint may not find the marker.
  const verificationKey = `magic:ok:${email}${state ? `:${state}` : ''}`
  const config = getSessionConfig()

  try {
    await kvSet(verificationKey, 1, config.TEMP_VERIFICATION_TTL_SECONDS)
    console.log('[MAGIC_CONFIRM][temp_marker_written]', { verificationKey: verificationKey.substring(0, 50) + '...' })

    // Read-back loop: wait until the marker is actually readable
    let readable = false
    for (let i = 0; i < 6; i++) {
      const check = await kvGet(verificationKey)
      if (check) { readable = true; break }
      await new Promise(r => setTimeout(r, 400 * (i + 1))) // 400ms, 800ms, 1200ms...
    }

    if (readable) {
      console.log('[MAGIC_CONFIRM][marker_confirmed_readable]')
    } else {
      console.warn('[MAGIC_CONFIRM][marker_write_ok_but_read_failed] — KV eventual consistency issue')
    }
  } catch (kvError: any) {
    console.error('[MAGIC_CONFIRM][marker_creation_failed]', { error: kvError?.message || String(kvError) })
  }

  try { await kafkaEmit('auth.combo_mfa_passed', { identifier: email, factor: 'magic', timestamp: Date.now() }) } catch { }
  try { const c = await getCounter({ name: 'auth_magic_confirm_success_total', help: 'Magic confirm success total' }); c.inc() } catch { }

  // Smart redirect based on context
  const base = process.env.NEXT_PUBLIC_URL || 'http://localhost:3000'

  // If this is a checkout flow, redirect to the done page (not checkout itself)
  // The original checkout tab detects verification via KV polling — opening a second
  // checkout tab causes duplicate-tab confusion. The done page will close itself
  // (desktop) or offer a "Go to Checkout" button (mobile/webview fallback).
  if (state?.startsWith('checkout-')) {
    const cartId = record?.cartId || state.replace('checkout-', '')

    // Generate signed proof so the verify endpoint can confirm identity
    // even if the KV marker hasn't propagated yet (Cloudflare KV eventual consistency)
    const proofTs = String(Date.now())
    const proofSecret = process.env.NEXTAUTH_SECRET || process.env.AUTH_SECRET || ''
    const proof = crypto.createHmac('sha256', proofSecret)
      .update(`${email}:${state}:${proofTs}`)
      .digest('hex')

    const doneUrl = `${base}/auth/magic/done?email=${encodeURIComponent(email)}&state=${encodeURIComponent(state)}${cartId ? `&cartId=${encodeURIComponent(cartId)}` : ''}${record?.phonePrimary ? `&phone=${encodeURIComponent(record.phonePrimary)}` : ''}&proof=${proof}&proofTs=${proofTs}`
    return new Response(null, { status: 302, headers: { Location: doneUrl } })
  }

  // For regular login flows, redirect to the new welcome page
  const welcomeUrl = `${base}/welcome?email=${encodeURIComponent(email)}${record?.phonePrimary ? `&phone=${encodeURIComponent(record.phonePrimary)}` : ''}${state ? `&state=${encodeURIComponent(state)}` : ''}`
  return new Response(null, { status: 302, headers: { Location: welcomeUrl } })
}

