            <div className={styles.container}>

              <h1 className={styles.title}>Checkout</h1>

              <div className="text-gray-600">

                {magicLinkProcessing ? 'Processing magic link verification...' : 'Loading your cart...'}

              </div>

            </div>

          </div>

        </div>

      </div>

    );

