                      </div>
                      <div className={styles.formGroup}>
                        <label htmlFor="cvv" className={styles.label}>CVV</label>
                        <input
                          type="text"
                          id="cvv"
                          name="cvv"
                          className={styles.input}
                          value={paymentDetails.cvv}
                          onChange={handlePaymentDetailsChange}
                          placeholder="Enter CVV"
                          required
